const express = require('express');
const axios = require('axios');

const app = express();
const PORT = 3000;

// Middleware to parse JSON bodies
app.use(express.json());

// POST endpoint to verify BVN
app.post('/verify-bvn', async (req, res) => {
  try {
    const { bvn } = req.body;

    // Validate BVN is provided
    if (!bvn) {
      return res.status(400).json({
        error: 'BVN is required',
        message: 'Please provide a BVN in the request body'
      });
    }

    // Get environment variables
    const appId = process.env.PREMBLY_APP_ID;
    const apiKey = process.env.PREMBLY_API_KEY;

    // Validate environment variables
    if (!appId || !apiKey) {
      return res.status(500).json({
        error: 'Missing credentials',
        message: 'PREMBLY_APP_ID and PREMBLY_API_KEY environment variables are required'
      });
    }

    // Call Prembly BVN verification API
    const response = await axios.post(
      'https://api.prembly.com/verification/bvn',
      {
        bvn: bvn
      },
      {
        headers: {
          'app-id': appId,
          'x-api-key': apiKey,
          'Content-Type': 'application/json'
        }
      }
    );

    // Return the data from Prembly
    return res.status(response.status).json(response.data);

  } catch (error) {
    console.error('Error verifying BVN:', error.message);

    // Handle axios errors
    if (error.response) {
      // The request was made and the server responded with a status code
      // that falls out of the range of 2xx
      return res.status(error.response.status).json({
        error: 'Prembly API error',
        message: error.response.data || 'Error from Prembly API'
      });
    } else if (error.request) {
      // The request was made but no response was received
      return res.status(503).json({
        error: 'Service unavailable',
        message: 'No response received from Prembly API'
      });
    } else {
      // Something happened in setting up the request that triggered an Error
      return res.status(500).json({
        error: 'Internal server error',
        message: 'An error occurred while processing the request'
      });
    }
  }
});

// Start the server
app.listen(PORT, () => {
  console.log(`BVN Verification Server running on port ${PORT}`);
  console.log(`POST endpoint available at http://localhost:${PORT}/verify-bvn`);
});

module.exports = app;

